    guestPrimaryLabel = 'INGRESA';
    /** Label of the secondary guest auth button — e.g. "REGISTRATE". */
    guestSecondaryLabel = 'REGISTRATE';
    /** Destination URL of the primary guest auth button. */
    guestPrimaryHref = '#';
    /** Destination URL of the secondary guest auth button. */
    guestSecondaryHref = '#';
    /** Label of the logout link shown in logged-in mode. */
    logoutLabel = 'Cerrar Sesión';
